import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function verifyCounterparty(chainName, counterpartyAddress) {
  const approvals = await client.SecurityService.getApprovals(chainName, counterpartyAddress);
  const riskItems = (approvals.data?.items ?? []).filter(a => (a.risk_score ?? 0) > 50);
  return {
    counterpartyAddress,
    riskScore: riskItems.length > 0 ? "HIGH" : "LOW",
    riskItems,
  };
}
